create table roma_main.ftth_fuzzy_requests (
    id              number
        generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 start with 1 nocache
        noorder nocycle nokeep noscale
    not null enable,
    request_beginn  timestamp(6) with time zone,
    request_ende    timestamp(6) with time zone,
    requests        number,
    datum_von       date,
    datum_bis       date,
    ftth_id         varchar2(100 byte),
    nur_neuzugaenge number(1, 0),
    username        varchar2(30 byte),
    errormessage    varchar2(4000 byte)
);

alter table roma_main.ftth_fuzzy_requests
    add constraint ftth_fuzzy_requests_pk primary key ( id )
        using index enable;

